	}

	if body.IsActive != nil {
		user.IsActive = *body.IsActive
	}

	user.UpdatedAt = time.Now()
	if err := h.repo.UpdateUser(user); err != nil {
		logrus.WithError(err).Error("Failed to update user")
		return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
			Error: "Failed to update user",
			Code:  http.StatusInternalServerError,
		})
	}

	adminID := middleware.GetUserID(c)
	details, _ := json.Marshal(map[string]string{
		"target_user": id,
	})
	h.repo.CreateAuditLog(&models.AuditLogEntry{
		UserID:     adminID,
		Action:     "update_user",
		EntityType: "user",
		EntityID:   id,
		Details:    details,
	})

	logrus.WithFields(logrus.Fields{
		"admin_id":    adminID,
		"target_user": id,
	}).Info("User updated")

	return c.JSON(http.StatusOK, user)
}

// DeleteUser soft-deletes a user by setting is_active to false.
func (h *UserHandler) DeleteUser(c echo.Context) error {
	id := c.Param("id")
	if id == "" {
		return c.JSON(http.StatusBadRequest, models.ErrorResponse{
			Error: "User ID is required",
			Code:  http.StatusBadRequest,
		})
	}

	user, err := h.repo.GetUserByID(id)
	if err != nil {
		return c.JSON(http.StatusNotFound, models.ErrorResponse{
			Error:   "User not found",
			Code:    http.StatusNotFound,
			Details: "No user found with the given ID",
		})
	}

	// Prevent self-deletion
	adminID := middleware.GetUserID(c)
	if adminID == id {
		return c.JSON(http.StatusBadRequest, models.ErrorResponse{
			Error:   "Cannot delete yourself",
			Code:    http.StatusBadRequest,
			Details: "You cannot deactivate your own account",
		})
	}

	user.IsActive = false
	user.UpdatedAt = time.Now()
	if err := h.repo.UpdateUser(user); err != nil {
		logrus.WithError(err).Error("Failed to soft-delete user")
		return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
			Error: "Failed to deactivate user",
			Code:  http.StatusInternalServerError,
		})
	}

	details, _ := json.Marshal(map[string]string{
		"target_user": id,
	})
	h.repo.CreateAuditLog(&models.AuditLogEntry{
		UserID:     adminID,
		Action:     "delete_user",
		EntityType: "user",
		EntityID:   id,
		Details:    details,
	})

	logrus.WithFields(logrus.Fields{
		"admin_id":    adminID,
		"target_user": id,
	}).Info("User soft-deleted")

	return c.JSON(http.StatusOK, map[string]string{
		"message": "User deactivated successfully",
	})
}

// UnlockUser resets lockout for a user.
func (h *UserHandler) UnlockUser(c echo.Context) error {
	id := c.Param("id")
	if id == "" {
		return c.JSON(http.StatusBadRequest, models.ErrorResponse{
			Error: "User ID is required",
			Code:  http.StatusBadRequest,
		})
	}

	// Verify user exists
	_, err := h.repo.GetUserByID(id)
	if err != nil {
		return c.JSON(http.StatusNotFound, models.ErrorResponse{
			Error:   "User not found",
			Code:    http.StatusNotFound,
			Details: "No user found with the given ID",
		})
	}

	if err := h.repo.UnlockUser(id); err != nil {
		logrus.WithError(err).Error("Failed to unlock user")
		return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
			Error: "Failed to unlock user",
			Code:  http.StatusInternalServerError,
		})
	}

	adminID := middleware.GetUserID(c)
	details, _ := json.Marshal(map[string]string{
		"target_user": id,
	})
	h.repo.CreateAuditLog(&models.AuditLogEntry{
		UserID:     adminID,
		Action:     "unlock_user",
		EntityType: "user",
		EntityID:   id,
		Details:    details,
	})

	logrus.WithFields(logrus.Fields{
		"admin_id":    adminID,
		"target_user": id,
	}).Info("User unlocked")

	return c.JSON(http.StatusOK, map[string]string{
		"message": "User unlocked successfully",
	})
}
"}

