	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("get stocktake: %w", err)
	}

	// Load lines
	rows, err := r.DB.Query(
		`SELECT id, stocktake_id, sku_id, batch_id, system_qty, counted_qty, variance, loss_reason
		 FROM stocktake_lines WHERE stocktake_id = $1`, id,
