		rows, err = r.DB.Query(
			`SELECT id, name, id_number_encrypted, phone, tier_id, points_balance, stored_value, status, frozen_at, expires_at, created_at,
			        COUNT(*) OVER() AS total
			 FROM members
			 WHERE name ILIKE $1 OR phone ILIKE $1
			 ORDER BY name
			 LIMIT $2 OFFSET $3`, pattern, pageSize, offset,
		)
	} else {
		rows, err = r.DB.Query(
			`SELECT id, name, id_number_encrypted, phone, tier_id, points_balance, stored_value, status, frozen_at, expires_at, created_at,
