      {error && <ErrorMessage message={error} onRetry={refetch} />}
      {!loading && !error && members.length === 0 && (
        <EmptyState message="No members found" actionLabel="Create Member" onAction={() => setShowCreate(true)} />
      )}
      {!loading && !error && members.length > 0 && (
