      setShowRedeem(false);
      setRedeemForm({ type: 'points_redeem', amount: '', package_id: '' });
      fetchMember();
      fetchTransactions(1);
    } catch (e: any) {
      setRedeemErr(e.response?.data?.error || 'Redemption failed');
    } finally {
      setActionLoading(false);
    }
