      return <span style={{ color: isNeg ? '#dc3545' : '#28a745', fontWeight: 500 }}>{isNeg ? '-' : '+'}{Math.abs(t.amount)}</span>;
    }},
    { key: 'description', header: 'Description' },
    { key: 'performed_by', header: 'By' },
  ];

