// RefundStoredValue refunds stored value if within 7 days and unused.
func (h *MemberHandler) RefundStoredValue(c echo.Context) error {
	id := c.Param("id")
	if id == "" {
		return c.JSON(http.StatusBadRequest, models.ErrorResponse{
			Error: "Member ID is required",
			Code:  http.StatusBadRequest,
		})
	}

	member, err := h.repo.GetMemberByID(id)
	if err != nil {
		return c.JSON(http.StatusNotFound, models.ErrorResponse{
			Error:   "Member not found",
			Code:    http.StatusNotFound,
			Details: "No member found with the given ID",
		})
	}

	var req struct {
		Amount float64 `json:"amount"`
	}
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, models.ErrorResponse{
			Error: "Invalid request body",
			Code:  http.StatusBadRequest,
		})
	}

	if req.Amount <= 0 {
		return c.JSON(http.StatusBadRequest, models.ErrorResponse{
			Error:   "Validation failed",
			Code:    http.StatusBadRequest,
			Details: "Amount must be greater than 0",
		})
	}

	// Check the most recent stored_value_add transaction
	lastAdd, err := h.repo.GetLatestStoredValueAdd(id)
	if err != nil {
		return c.JSON(http.StatusBadRequest, models.ErrorResponse{
			Error:   "No stored value addition found",
			Code:    http.StatusBadRequest,
			Details: "No recent stored value addition to refund",
		})
	}

	// Check within 7 days
	if time.Since(lastAdd.CreatedAt) > 7*24*time.Hour {
		return c.JSON(http.StatusBadRequest, models.ErrorResponse{
			Error:   "Refund period expired",
			Code:    http.StatusBadRequest,
			Details: "Refunds must be requested within 7 days of the stored value addition",
		})
	}

	// Check amount not used (member still has enough balance)
	if member.StoredValue < req.Amount {
		return c.JSON(http.StatusBadRequest, models.ErrorResponse{
			Error:   "Insufficient balance for refund",
			Code:    http.StatusBadRequest,
			Details: "The stored value has already been partially or fully used",
		})
	}

	// Check refund amount doesn't exceed the original addition
	if req.Amount > lastAdd.Amount {
		return c.JSON(http.StatusBadRequest, models.ErrorResponse{
			Error:   "Refund exceeds original amount",
			Code:    http.StatusBadRequest,
			Details: fmt.Sprintf("Cannot refund more than the original addition of $%.2f", lastAdd.Amount),
		})
	}

	member.StoredValue -= req.Amount
	if err := h.repo.UpdateMember(member); err != nil {
		logrus.WithError(err).Error("Failed to refund stored value")
		return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
			Error: "Failed to process refund",
			Code:  http.StatusInternalServerError,
		})
	}

	userID := middleware.GetUserID(c)
	h.repo.CreateMemberTransaction(&models.MemberTransaction{
		ID:          uuid.New().String(),
		MemberID:    id,
		Type:        "stored_value_refund",
		Amount:      -req.Amount,
		Description: fmt.Sprintf("Refunded stored value: $%.2f", req.Amount),
		PerformedBy: userID,
		CreatedAt:   time.Now(),
	})

	details, _ := json.Marshal(map[string]interface{}{
		"amount": req.Amount,
	})
	h.repo.CreateAuditLog(&models.AuditLogEntry{
		UserID:     userID,
		Action:     "refund_stored_value",
		EntityType: "member",
		EntityID:   id,
		Details:    details,
	})

	logrus.WithFields(logrus.Fields{
		"user_id":   userID,
		"member_id": id,
		"amount":    req.Amount,
	}).Info("Stored value refunded")

	member, _ = h.repo.GetMemberByID(id)
	return c.JSON(http.StatusOK, member)
}

// ListTransactions returns transactions for a member.
func (h *MemberHandler) ListTransactions(c echo.Context) error {
	memberID := c.Param("id")
	if memberID == "" {
		return c.JSON(http.StatusBadRequest, models.ErrorResponse{
			Error: "Member ID is required",
			Code:  http.StatusBadRequest,
		})
	}

	// Verify member exists
	if _, err := h.repo.GetMemberByID(memberID); err != nil {
		return c.JSON(http.StatusNotFound, models.ErrorResponse{
			Error:   "Member not found",
			Code:    http.StatusNotFound,
			Details: "No member found with the given ID",
		})
	}

	page, _ := strconv.Atoi(c.QueryParam("page"))
	pageSize, _ := strconv.Atoi(c.QueryParam("page_size"))
	if page < 1 {
		page = 1
	}
	if pageSize < 1 || pageSize > 100 {
		pageSize = 20
	}

	transactions, total, err := h.repo.ListMemberTransactions(memberID, page, pageSize)
	if err != nil {
		logrus.WithError(err).Error("Failed to list member transactions")
		return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
			Error: "Failed to retrieve transactions",
			Code:  http.StatusInternalServerError,
		})
	}

	return c.JSON(http.StatusOK, models.PaginatedResponse{
		Data:     transactions,
		Total:    total,
		Page:     page,
		PageSize: pageSize,
	})
}

// ListTiers returns all membership tiers.
func (h *MemberHandler) ListTiers(c echo.Context) error {
	tiers, err := h.repo.ListTiers()
	if err != nil {
		logrus.WithError(err).Error("Failed to list tiers")
		return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
			Error: "Failed to retrieve tiers",
			Code:  http.StatusInternalServerError,
		})
	}

	return c.JSON(http.StatusOK, map[string]interface{}{
		"data": tiers,
	})
}
"}

