{"file_path": "C:/Users/betea/Documents/projects/eaglepoint/Task-w2t129/repo/backend/internal/repository/repository.go", "content": "package repository

import (
	"database/sql"
	"fmt"
	"strings"
	"time"

	"github.com/google/uuid"
	"github.com/lib/pq"

	"medops/internal/models"
)

// Repository wraps a *sql.DB and provides methods for all database operations.
type Repository struct {
	DB *sql.DB
}

// New creates a new Repository with the given database connection.
func New(db *sql.DB) *Repository {
	return &Repository{DB: db}
}

// ---------- Auth ----------

// GetUserByUsername retrieves a user by their username.
func (r *Repository) GetUserByUsername(username string) (*models.User, error) {
	u := &models.User{}
	err := r.DB.QueryRow(
		`SELECT id, username, password_hash, role, failed_attempts, locked_until, is_active, created_at, updated_at
		 FROM auth_users WHERE username = $1`, username,
	).Scan(&u.ID, &u.Username, &u.PasswordHash, &u.Role, &u.FailedAttempts, &u.LockedUntil, &u.IsActive, &u.CreatedAt, &u.UpdatedAt)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("get user by username: %w", err)
	}
	return u, nil
}

// GetUserByID retrieves a user by their ID.
func (r *Repository) GetUserByID(id string) (*models.User, error) {
	u := &models.User{}
	err := r.DB.QueryRow(
		`SELECT id, username, password_hash, role, failed_attempts, locked_until, is_active, created_at, updated_at
		 FROM auth_users WHERE id = $1`, id,
	).Scan(&u.ID, &u.Username, &u.PasswordHash, &u.Role, &u.FailedAttempts, &u.LockedUntil, &u.IsActive, &u.CreatedAt, &u.UpdatedAt)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("get user by id: %w", err)
	}
	return u, nil
}

// CreateUser inserts a new user into the database.
func (r *Repository) CreateUser(user *models.User) error {
	if user.ID == "" {
		user.ID = uuid.New().String()
	}
	now := time.Now()
	user.CreatedAt = now
	user.UpdatedAt = now
	_, err := r.DB.Exec(
		`INSERT INTO auth_users (id, username, password_hash, role, failed_attempts, locked_until, is_active, created_at, updated_at)
		 VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)`,
		user.ID, user.Username, user.PasswordHash, user.Role, user.FailedAttempts, user.LockedUntil, user.IsActive, user.CreatedAt, user.UpdatedAt,
	)
	if err != nil {
		return fmt.Errorf("create user: %w", err)
	}
	return nil
}

// UpdateUser updates an existing user.
func (r *Repository) UpdateUser(user *models.User) error {
	user.UpdatedAt = time.Now()
	_, err := r.DB.Exec(
		`UPDATE auth_users SET username=$1, password_hash=$2, role=$3, is_active=$4, updated_at=$5 WHERE id=$6`,
		user.Username, user.PasswordHash, user.Role, user.IsActive, user.UpdatedAt, user.ID,
	)
	if err != nil {
		return fmt.Errorf("update user: %w", err)
	}
	return nil
}

// ListUsers returns all users.
func (r *Repository) ListUsers() ([]models.User, error) {
	rows, err := r.DB.Query(
		`SELECT id, username, password_hash, role, failed_attempts, locked_until, is_active, created_at, updated_at
		 FROM auth_users ORDER BY created_at DESC`,
	)
	if err != nil {
		return nil, fmt.Errorf("list users: %w", err)
	}
	defer rows.Close()

	var users []models.User
	for rows.Next() {
		var u models.User
		if err := rows.Scan(&u.ID, &u.Username, &u.PasswordHash, &u.Role, &u.FailedAttempts, &u.LockedUntil, &u.IsActive, &u.CreatedAt, &u.UpdatedAt); err != nil {
			return nil, fmt.Errorf("list users scan: %w", err)
		}
		users = append(users, u)
	}
	return users, rows.Err()
}

// IncrementFailedAttempts increments the failed login attempts counter.
func (r *Repository) IncrementFailedAttempts(userID string) error {
