		rows, err = r.DB.Query(
			`SELECT id, ndc, upc, name, description, unit_of_measure, low_stock_threshold, storage_location, is_active, created_at,
			        COUNT(*) OVER() AS total
			 FROM skus
			 WHERE name ILIKE $1 OR ndc ILIKE $1 OR upc ILIKE $1
			 ORDER BY name
			 LIMIT $2 OFFSET $3`, pattern, pageSize, offset,
		)
	} else {
		rows, err = r.DB.Query(
			`SELECT id, ndc, upc, name, description, unit_of_measure, low_stock_threshold, storage_location, is_active, created_at,
