815	// GetWorkOrderAnalytics returns basic work order statistics.
816	func (r *Repository) GetWorkOrderAnalytics() (map[string]interface{}, error) {
817		analytics := make(map[string]interface{})
818	
819		// Count by status
820		rows, err := r.DB.Query(`SELECT status, COUNT(*) FROM work_orders GROUP BY status`)
821		if err != nil {
822			return nil, fmt.Errorf("work order analytics by_status: %w", err)
823		}
824		defer rows.Close()
825	
826		statusCounts := make(map[string]int)
827		for rows.Next() {
828			var status string
829			var count int
830			if err := rows.Scan(&status, &count); err != nil {
831				return nil, fmt.Errorf("work order analytics by_status scan: %w", err)
832			}
833			statusCounts[status] = count
834		}
835		if err := rows.Err(); err != nil {
836			return nil, err
837		}
838		analytics["by_status"] = statusCounts
839	
840		// Average resolution time (hours) for closed orders
841		var avgHours sql.NullFloat64
842		err = r.DB.QueryRow(
843			`SELECT AVG(EXTRACT(EPOCH FROM (closed_at - created_at)) / 3600)
844			 FROM work_orders WHERE status = 'closed' AND closed_at IS NOT NULL`,
845		).Scan(&avgHours)
846		if err != nil {
847			return nil, fmt.Errorf("work order analytics avg_resolution: %w", err)
848		}
849		if avgHours.Valid {
850			analytics["avg_resolution_hours"] = avgHours.Float64
851		} else {
852			analytics["avg_resolution_hours"] = 0
853		}
854	
855		// Total costs for closed orders
856		var totalParts, totalLabor sql.NullFloat64
857		err = r.DB.QueryRow(
858			`SELECT COALESCE(SUM(parts_cost), 0), COALESCE(SUM(labor_cost), 0) FROM work_orders WHERE status = 'closed'`,
859		).Scan(&totalParts, &totalLabor)
860		if err != nil {
861			return nil, fmt.Errorf("work order analytics costs: %w", err)
862		}
863		analytics["total_parts_cost"] = totalParts.Float64
864		analytics["total_labor_cost"] = totalLabor.Float64
865	
866		// Average rating
867		var avgRating sql.NullFloat64
868		err = r.DB.QueryRow(`SELECT AVG(rating) FROM work_orders WHERE rating IS NOT NULL`).Scan(&avgRating)
869		if err != nil {
870			return nil, fmt.Errorf("work order analytics avg_rating: %w", err)
871		}
872		if avgRating.Valid {
873			analytics["avg_rating"] = avgRating.Float64
874		} else {
875			analytics["avg_rating"] = 0
876		}
877	
878		return analytics, nil
879	}
