                  <h4 style={{ margin: '0 0 0.5rem', color: '#155724' }}>Confirm Approval</h4>
                  <p style={{ fontSize: '0.9rem', color: '#155724', margin: '0 0 0.75rem' }}>
                    Are you sure you want to approve this statement for ${selectedStatement.total_amount.toFixed(2)}?
                    This action cannot be undone.
                  </p>
                  <div style={{ display: 'flex', gap: '0.5rem' }}>
                    <button onClick={handleApprove} disabled={actionLoading} style={actionLoading ? btnDisabled : btnSuccess}>
                      {actionLoading ? 'Approving...' : 'Yes, Approve'}
                    </button>
                    <button onClick={() => { setShowApproveConfirm(false); setApproveStep(0); }} style={btnSecondary}>Cancel</button>
                  </div>
                </div>
              )}
            </>
          )}
        </Modal>
      )}
    </div>
  );
};

export default StatementsPage;
"}

