1	import React, { useState } from 'react';
2	
3	interface Column<T> {
4	  key: string;
5	  header: string;
6	  render?: (item: T) => React.ReactNode;
7	  sortable?: boolean;
8	}
9	
10	interface Props<T> {
11	  columns: Column<T>[];
12	  data: T[];
13	  onRowClick?: (item: T) => void;
14	  onContextMenu?: (item: T, e: React.MouseEvent) => void;
15	  keyField?: string;
16	}
17	
18	function DataTable<T extends Record<string, any>>({ columns, data, onRowClick, onContextMenu, keyField = 'id' }: Props<T>) {
19	  const [sortKey, setSortKey] = useState<string>('');
20	  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('asc');
21	
22	  const sorted = [...data].sort((a, b) => {
23	    if (!sortKey) return 0;
24	    const aVal = a[sortKey], bVal = b[sortKey];
25	    const cmp = aVal < bVal ? -1 : aVal > bVal ? 1 : 0;
26	    return sortDir === 'asc' ? cmp : -cmp;
27	  });
28	
29	  const handleSort = (key: string) => {
30	    if (sortKey === key) setSortDir(d => d === 'asc' ? 'desc' : 'asc');
31	    else { setSortKey(key); setSortDir('asc'); }
32	  };
33	
34	  return (
35	    <div style={{ overflowX: 'auto' }}>
36	      <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
37	        <thead>
38	          <tr style={{ backgroundColor: '#f5f5f5', borderBottom: '2px solid #ddd' }}>
39	            {columns.map(col => (
40	              <th key={col.key} onClick={() => col.sortable && handleSort(col.key)}
41	                style={{ padding: '0.75rem', textAlign: 'left', cursor: col.sortable ? 'pointer' : 'default', userSelect: 'none', whiteSpace: 'nowrap' }}>
42	                {col.header} {sortKey === col.key ? (sortDir === 'asc' ? ' ▲' : ' ▼') : ''}
43	              </th>
44	            ))}
45	          </tr>
46	        </thead>
47	        <tbody>
48	          {sorted.map((item) => (
49	            <tr key={item[keyField]}
50	              onClick={() => onRowClick?.(item)}
51	              onContextMenu={(e) => { e.preventDefault(); onContextMenu?.(item, e); }}
52	              style={{ borderBottom: '1px solid #eee', cursor: onRowClick ? 'pointer' : 'default' }}
53	              onMouseEnter={e => (e.currentTarget.style.backgroundColor = '#f9f9f9')}
54	              onMouseLeave={e => (e.currentTarget.style.backgroundColor = 'transparent')}>
55	              {columns.map(col => (
56	                <td key={col.key} style={{ padding: '0.75rem' }}>
57	                  {col.render ? col.render(item) : String(item[col.key] ?? '')}
58	                </td>
59	              ))}
60	            </tr>
61	          ))}
62	        </tbody>
63	      </table>
64	    </div>
65	  );
66	}
67	
68	export default DataTable;
