13	  const login = useCallback(async (username: string, password: string) => {
14	    setLoading(true);
15	    setError(null);
16	    try {
17	      const res = await authAPI.login(username, password);
18	      const { token, user: userData } = res.data;
19	      localStorage.setItem('medops_token', token);
20	      localStorage.setItem('medops_user', JSON.stringify(userData));
21	      setUser(userData);
22	      return userData;
23	    } catch (err: any) {
24	      const msg = err.response?.data?.error || 'Login failed';
25	      setError(msg);
26	      throw new Error(msg);
27	    } finally {
28	      setLoading(false);
29	    }
30	  }, []);
31	
32	  const logout = useCallback(async () => {
33	    try {
34	      await authAPI.logout();
35	    } catch {
36	      // ignore
37	    }
38	    localStorage.removeItem('medops_token');
39	    localStorage.removeItem('medops_user');
40	    setUser(null);
41	  }, []);
42	
43	  const isAuthenticated = !!user;
44	  const hasRole = useCallback(
45	    (roles: string[]) => user ? roles.includes(user.role) : false,
46	    [user]
47	  );
48	
49	  return { user, loading, error, login, logout, isAuthenticated, hasRole };
50	}
