293	// UnfreezeMember sets a member's status back to active and extends expiry.
294	func (h *MemberHandler) UnfreezeMember(c echo.Context) error {
295		id := c.Param("id")
296		if id == "" {
297			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
298				Error: "Member ID is required",
