302	
303		member, err := h.repo.GetMemberByID(id)
304		if err != nil {
305			return c.JSON(http.StatusNotFound, models.ErrorResponse{
306				Error:   "Member not found",
307				Code:    http.StatusNotFound,
308				Details: "No member found with the given ID",
309			})
310		}
311	
312		if member.Status != "frozen" {
313			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
314				Error:   "Member not frozen",
315				Code:    http.StatusBadRequest,
316				Details: "Can only unfreeze a frozen member",
