324			member.ExpiresAt = member.ExpiresAt.Add(frozenDuration)
325		}
326	
327		member.Status = "active"
328		member.FrozenAt = nil
329	
330		if err := h.repo.UpdateMember(member); err != nil {
331			logrus.WithError(err).Error("Failed to unfreeze member")
