357	func (h *MemberHandler) RedeemBenefit(c echo.Context) error {
358		id := c.Param("id")
359		if id == "" {
360			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
361				Error: "Member ID is required",
362				Code:  http.StatusBadRequest,
363			})
364		}
365	
366		member, err := h.repo.GetMemberByID(id)
367		if err != nil {
368			return c.JSON(http.StatusNotFound, models.ErrorResponse{
369				Error:   "Member not found",
370				Code:    http.StatusNotFound,
371				Details: "No member found with the given ID",
372			})
373		}
374	
375		// Check member is not expired
376		if time.Now().After(member.ExpiresAt) {
377			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
378				Error:   "Membership expired",
379				Code:    http.StatusBadRequest,
380				Details: "This membership has expired",
381			})
382		}
383	
