1	import { useState, useEffect, useCallback } from 'react';
2	
3	interface FetchState<T> {
4	  data: T | null;
5	  loading: boolean;
6	  error: string | null;
7	  refetch: () => void;
8	}
9	
10	export function useFetch<T>(fetchFn: () => Promise<{ data: T }>, deps: unknown[] = []): FetchState<T> {
11	  const [data, setData] = useState<T | null>(null);
12	  const [loading, setLoading] = useState(true);
13	  const [error, setError] = useState<string | null>(null);
14	
15	  const fetch = useCallback(async () => {
16	    setLoading(true);
17	    setError(null);
18	    try {
19	      const res = await fetchFn();
20	      setData(res.data);
21	    } catch (err: any) {
22	      setError(err.response?.data?.error || err.message || 'An error occurred');
23	    } finally {
24	      setLoading(false);
25	    }
26	  }, deps);
27	
28	  useEffect(() => {
29	    fetch();
30	  }, [fetch]);
31	
32	  return { data, loading, error, refetch: fetch };
33	}
