220	func (h *ChargeHandler) ImportRateTableCSV(c echo.Context) error {
221		id := c.Param("id")
222		if id == "" {
223			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
224				Error: "Rate table ID is required",
225				Code:  http.StatusBadRequest,
226			})
227		}
228	
229		rt, err := h.repo.GetRateTableByID(id)
230		if err != nil {
231			return c.JSON(http.StatusNotFound, models.ErrorResponse{
232				Error:   "Rate table not found",
233				Code:    http.StatusNotFound,
234				Details: "No rate table found with the given ID",
235			})
236		}
237	
238		file, err := c.FormFile("file")
239		if err != nil {
240			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
241				Error:   "File upload required",
242				Code:    http.StatusBadRequest,
243				Details: "A CSV file must be uploaded",
244			})
245		}
246	
247		src, err := file.Open()
248		if err != nil {
249			logrus.WithError(err).Error("Failed to open uploaded CSV")
250			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
251				Error: "Failed to process uploaded file",
252				Code:  http.StatusInternalServerError,
253			})
254		}
255		defer src.Close()
256	
257		reader := csv.NewReader(src)
258		records, err := reader.ReadAll()
259		if err != nil {
260			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
261				Error:   "Invalid CSV file",
262				Code:    http.StatusBadRequest,
263				Details: "Failed to parse CSV data",
264			})
265		}
266	
267		if len(records) < 2 {
268			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
269				Error:   "Empty CSV",
270				Code:    http.StatusBadRequest,
271				Details: "CSV must contain a header row and at least one data row",
272			})
273		}
274	
275		// Parse CSV rows into tier objects
276		var tiers []map[string]interface{}
277		headers := records[0]
278		for _, row := range records[1:] {
279			tier := make(map[string]interface{})
280			for i, header := range headers {
281				if i < len(row) {
282					// Try to parse as number
283					header = strings.TrimSpace(header)
284					val := strings.TrimSpace(row[i])
285					if num, err := strconv.ParseFloat(val, 64); err == nil {
286						tier[header] = num
287					} else {
288						tier[header] = val
289					}
290				}
291			}
292			tiers = append(tiers, tier)
293		}
294	
295		tiersJSON, err := json.Marshal(tiers)
296		if err != nil {
297			logrus.WithError(err).Error("Failed to marshal tiers")
298			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
299				Error: "Failed to process tier data",
300				Code:  http.StatusInternalServerError,
301			})
302		}
303	
304		rt.Tiers = tiersJSON
305		if err := h.repo.UpdateRateTable(rt); err != nil {
306			logrus.WithError(err).Error("Failed to update rate table with CSV tiers")
307			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
308				Error: "Failed to import rate table tiers",
309				Code:  http.StatusInternalServerError,
310			})
311		}
312	
313		userID := middleware.GetUserID(c)
314		details, _ := json.Marshal(map[string]interface{}{
315			"rate_table_id": id,
316			"tiers_count":   len(tiers),
317		})
318		h.repo.CreateAuditLog(&models.AuditLogEntry{
319			UserID:     userID,
320			Action:     "import_rate_table_csv",
