406		}
407	
408		if req.PeriodStart == "" || req.PeriodEnd == "" {
409			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
410				Error:   "Validation failed",
411				Code:    http.StatusBadRequest,
412				Details: "Period start and end dates are required",
413			})
414		}
415	
416		if _, err := time.Parse("2006-01-02", req.PeriodStart); err != nil {
417			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
418				Error:   "Validation failed",
419				Code:    http.StatusBadRequest,
420				Details: "Invalid period_start format. Use YYYY-MM-DD",
421			})
422		}
423		if _, err := time.Parse("2006-01-02", req.PeriodEnd); err != nil {
424			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
425				Error:   "Validation failed",
426				Code:    http.StatusBadRequest,
427				Details: "Invalid period_end format. Use YYYY-MM-DD",
428			})
429		}
430	
431		// Calculate total amount from line items
432		var totalAmount float64
433		for i := range req.LineItems {
434			item := &req.LineItems[i]
435			item.Total = (item.Quantity * item.UnitPrice) + item.Surcharge + item.Tax
436			totalAmount += item.Total
437		}
438	
439		statement := &models.ChargeStatement{
440			ID:          uuid.New().String(),
441			PeriodStart: req.PeriodStart,
442			PeriodEnd:   req.PeriodEnd,
443			TotalAmount: totalAmount,
444			Status:      "draft",
445			CreatedAt:   time.Now(),
446		}
447	
448		if err := h.repo.CreateStatement(statement); err != nil {
449			logrus.WithError(err).Error("Failed to create statement")
450			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
451				Error: "Failed to create statement",
452				Code:  http.StatusInternalServerError,
453			})
454		}
455	
456		// Create line items
457		for i := range req.LineItems {
458			item := &req.LineItems[i]
459			item.ID = uuid.New().String()
460			item.StatementID = statement.ID
461			if err := h.repo.CreateChargeLineItem(item); err != nil {
462				logrus.WithError(err).Error("Failed to create line item")
463			}
464		}
465	
466		userID := middleware.GetUserID(c)
467		details, _ := json.Marshal(map[string]interface{}{
468			"period_start": req.PeriodStart,
469			"period_end":   req.PeriodEnd,
470			"total_amount": totalAmount,
471		})
472		h.repo.CreateAuditLog(&models.AuditLogEntry{
473			UserID:     userID,
474			Action:     "generate_statement",
475			EntityType: "charge_statement",
476			EntityID:   statement.ID,
477			Details:    details,
478		})
479	
480		logrus.WithFields(logrus.Fields{
481			"user_id":      userID,
482			"statement_id": statement.ID,
483		}).Info("Statement generated")
484	
485		return c.JSON(http.StatusCreated, map[string]interface{}{
486			"statement":  statement,
487			"line_items": req.LineItems,
488		})
489	}
490	
491	// ReconcileStatement reconciles a statement, requiring variance notes if delta > $25.
492	func (h *ChargeHandler) ReconcileStatement(c echo.Context) error {
493		id := c.Param("id")
494		if id == "" {
495			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
496				Error: "Statement ID is required",
497				Code:  http.StatusBadRequest,
498			})
499		}
500	
501		statement, err := h.repo.GetStatementByID(id)
502		if err != nil {
503			return c.JSON(http.StatusNotFound, models.ErrorResponse{
504				Error:   "Statement not found",
505				Code:    http.StatusNotFound,
506				Details: "No statement found with the given ID",
507			})
508		}
509	
510		var req struct {
511			ActualAmount  float64 `json:"actual_amount"`
512			VarianceNotes string  `json:"variance_notes"`
513		}
514		if err := c.Bind(&req); err != nil {
515			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
516				Error: "Invalid request body",
517				Code:  http.StatusBadRequest,
518			})
519		}
520	
521		// Check if variance exceeds $25
522		delta := req.ActualAmount - statement.TotalAmount
523		if delta < 0 {
524			delta = -delta
525		}
526		if delta > 25 && req.VarianceNotes == "" {
527			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
528				Error:   "Variance notes required",
529				Code:    http.StatusBadRequest,
530				Details: "Variance notes are required when the delta exceeds $25",
531			})
532		}
533	
534		if req.VarianceNotes != "" {
535			statement.VarianceNotes = &req.VarianceNotes
536		}
537		statement.Status = "reconciled"
538		statement.TotalAmount = req.ActualAmount
539	
540		if err := h.repo.UpdateStatement(statement); err != nil {
541			logrus.WithError(err).Error("Failed to reconcile statement")
542			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
543				Error: "Failed to reconcile statement",
544				Code:  http.StatusInternalServerError,
545			})
546		}
547	
548		userID := middleware.GetUserID(c)
549		details, _ := json.Marshal(map[string]interface{}{
550			"statement_id": id,
551			"delta":        delta,
552		})
553		h.repo.CreateAuditLog(&models.AuditLogEntry{
554			UserID:     userID,
555			Action:     "reconcile_statement",
556			EntityType: "charge_statement",
557			EntityID:   id,
558			Details:    details,
559		})
560	
561		logrus.WithFields(logrus.Fields{
562			"user_id":      userID,
563			"statement_id": id,
564			"delta":        delta,
565		}).Info("Statement reconciled")
566	
567		return c.JSON(http.StatusOK, statement)
568	}
569	
570	// ApproveStatement implements two-step approval for statements.
571	func (h *ChargeHandler) ApproveStatement(c echo.Context) error {
572		id := c.Param("id")
573		if id == "" {
574			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
575				Error: "Statement ID is required",
576				Code:  http.StatusBadRequest,
577			})
578		}
579	
580		statement, err := h.repo.GetStatementByID(id)
581		if err != nil {
582			return c.JSON(http.StatusNotFound, models.ErrorResponse{
583				Error:   "Statement not found",
584				Code:    http.StatusNotFound,
585				Details: "No statement found with the given ID",
586			})
587		}
588	
589		userID := middleware.GetUserID(c)
590	
591		// Cannot approve own statement (check if current user created it)
592		// Since statement doesn't have a created_by field, we check against existing approvers
593	
594		if statement.ApprovedBy1 == nil {
595			// First approval
596			statement.ApprovedBy1 = &userID
597			statement.Status = "pending_approval_2"
598		} else if statement.ApprovedBy2 == nil {
599			// Second approval — must be different user
600			if *statement.ApprovedBy1 == userID {
601				return c.JSON(http.StatusForbidden, models.ErrorResponse{
602					Error:   "Cannot approve twice",
603					Code:    http.StatusForbidden,
604					Details: "The second approver must be a different user than the first",
605				})
606			}
607			statement.ApprovedBy2 = &userID
608			statement.Status = "approved"
609		} else {
610			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
611				Error:   "Statement already fully approved",
612				Code:    http.StatusBadRequest,
613				Details: "This statement has already been approved by two users",
614			})
615		}
616	
617		if err := h.repo.UpdateStatement(statement); err != nil {
618			logrus.WithError(err).Error("Failed to approve statement")
619			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
620				Error: "Failed to approve statement",
621				Code:  http.StatusInternalServerError,
622			})
623		}
624	
625		details, _ := json.Marshal(map[string]interface{}{
626			"statement_id": id,
627			"approval_step": func() int {
628				if statement.ApprovedBy2 != nil {
629					return 2
630				}
631				return 1
632			}(),
633		})
634		h.repo.CreateAuditLog(&models.AuditLogEntry{
635			UserID:     userID,
636			Action:     "approve_statement",
637			EntityType: "charge_statement",
638			EntityID:   id,
639			Details:    details,
640		})
641	
642		logrus.WithFields(logrus.Fields{
643			"user_id":      userID,
644			"statement_id": id,
645		}).Info("Statement approved")
646	
647		return c.JSON(http.StatusOK, statement)
648	}
649	
650	// ExportStatement exports a statement as CSV or JSON with HMAC signature.
651	func (h *ChargeHandler) ExportStatement(c echo.Context) error {
652		id := c.Param("id")
653		if id == "" {
654			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
655				Error: "Statement ID is required",
656				Code:  http.StatusBadRequest,
657			})
658		}
659	
660		statement, err := h.repo.GetStatementByID(id)
661		if err != nil {
662			return c.JSON(http.StatusNotFound, models.ErrorResponse{
663				Error:   "Statement not found",
664				Code:    http.StatusNotFound,
665				Details: "No statement found with the given ID",
666			})
667		}
668	
669		lineItems, err := h.repo.GetStatementLineItems(id)
670		if err != nil {
671			logrus.WithError(err).Error("Failed to get statement line items for export")
672			lineItems = []models.ChargeLineItem{}
673		}
674	
675		format := c.QueryParam("format")
676		if format == "" {
677			format = "json"
678		}
679	
680		var content []byte
681		var contentType string
682	
683		switch format {
684		case "csv":
685			contentType = "text/csv"
686			var sb strings.Builder
687			writer := csv.NewWriter(&sb)
688	
689			// Header
690			writer.Write([]string{"ID", "Period Start", "Period End", "Total Amount", "Status"})
691			writer.Write([]string{statement.ID, statement.PeriodStart, statement.PeriodEnd,
692				fmt.Sprintf("%.2f", statement.TotalAmount), statement.Status})
693	
694			writer.Write([]string{}) // blank line
695			writer.Write([]string{"Line Item ID", "Description", "Quantity", "Unit Price", "Surcharge", "Tax", "Total"})
696	
697			for _, item := range lineItems {
698				writer.Write([]string{
699					item.ID,
700					item.Description,
701					fmt.Sprintf("%.2f", item.Quantity),
702					fmt.Sprintf("%.2f", item.UnitPrice),
703					fmt.Sprintf("%.2f", item.Surcharge),
704					fmt.Sprintf("%.2f", item.Tax),
705					fmt.Sprintf("%.2f", item.Total),
706				})
707			}
708			writer.Flush()
709			content = []byte(sb.String())
710	
711		default: // json
712			contentType = "application/json"
713			exportData := map[string]interface{}{
714				"statement":  statement,
715				"line_items": lineItems,
716				"exported_at": time.Now().UTC().Format(time.RFC3339),
717			}
718			content, err = json.MarshalIndent(exportData, "", "  ")
719			if err != nil {
720				logrus.WithError(err).Error("Failed to marshal export data")
721				return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
722					Error: "Failed to export statement",
723					Code:  http.StatusInternalServerError,
724				})
725			}
726		}
727	
728		// Compute HMAC-SHA256 signature
729		hmacKey := []byte("medops-export-signing-key")
730		mac := hmac.New(sha256.New, hmacKey)
731		mac.Write(content)
732		signature := hex.EncodeToString(mac.Sum(nil))
733	
734		// Mark statement as exported
735		now := time.Now()
736		statement.ExportedAt = &now
737		h.repo.UpdateStatement(statement)
738	
739		userID := middleware.GetUserID(c)
740		details, _ := json.Marshal(map[string]string{
741			"statement_id": id,
742			"format":       format,
743		})
744		h.repo.CreateAuditLog(&models.AuditLogEntry{
745			UserID:     userID,
746			Action:     "export_statement",
747			EntityType: "charge_statement",
748			EntityID:   id,
749			Details:    details,
750		})
751	
752		c.Response().Header().Set("Content-Type", contentType)
753		c.Response().Header().Set("X-HMAC-Signature", signature)
754		c.Response().Header().Set("Content-Disposition", fmt.Sprintf("attachment; filename=\"statement_%s.%s\"", id, format))
755	
756		return c.Blob(http.StatusOK, contentType, content)
757	}
758	
759	// Ensure io import is used (for ImportRateTableCSV)
760	var _ = io.EOF
761	
