func (h *SystemHandler) DeleteDraft(c echo.Context) error {
	id := c.Param("id")
	if id == "" {
		return c.JSON(http.StatusBadRequest, models.ErrorResponse{
			Error: "Draft ID is required",
			Code:  http.StatusBadRequest,
		})
	}

	draft, err := h.repo.GetDraftByID(id)
