79	// UpdateConfig updates a system configuration value.
80	func (h *SystemHandler) UpdateConfig(c echo.Context) error {
81		var req struct {
82			Key   string `json:"key"`
83			Value string `json:"value"`
84		}
85		if err := c.Bind(&req); err != nil {
86			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
87				Error: "Invalid request body",
88				Code:  http.StatusBadRequest,
89			})
90		}
91	
92		if req.Key == "" {
93			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
94				Error:   "Validation failed",
95				Code:    http.StatusBadRequest,
96				Details: "Configuration key is required",
97			})
98		}
99	
100		if err := h.repo.UpdateConfig(req.Key, req.Value); err != nil {
101			logrus.WithError(err).Error("Failed to update system config")
102			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
103				Error: "Failed to update system configuration",
104				Code:  http.StatusInternalServerError,
105			})
106		}
107	
108		userID := middleware.GetUserID(c)
109		details, _ := json.Marshal(map[string]string{
110			"key": req.Key,
111		})
112		h.repo.CreateAuditLog(&models.AuditLogEntry{
113			UserID:     userID,
114			Action:     "update_config",
115			EntityType: "system_config",
116			EntityID:   req.Key,
117			Details:    details,
118		})
119	
120		logrus.WithFields(logrus.Fields{
121			"user_id": userID,
122			"key":     req.Key,
123		}).Info("System config updated")
124	
125		return c.JSON(http.StatusOK, map[string]string{
126			"message": "Configuration updated successfully",
127			"key":     req.Key,
128		})
129	}
