132	func (h *SystemHandler) SaveDraft(c echo.Context) error {
133		userID := middleware.GetUserID(c)
134	
135		var req struct {
136			FormType  string          `json:"form_type"`
137			FormID    *string         `json:"form_id"`
138			StateJSON json.RawMessage `json:"state_json"`
139		}
140		if err := c.Bind(&req); err != nil {
141			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
142				Error: "Invalid request body",
143				Code:  http.StatusBadRequest,
144			})
145		}
146	
147		if req.FormType == "" {
148			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
149				Error:   "Validation failed",
150				Code:    http.StatusBadRequest,
151				Details: "Form type is required",
152			})
153		}
154		if req.StateJSON == nil {
155			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
156				Error:   "Validation failed",
157				Code:    http.StatusBadRequest,
158				Details: "State JSON is required",
159			})
160		}
161	
162		draft := &models.DraftCheckpoint{
163			ID:        uuid.New().String(),
164			UserID:    userID,
165			FormType:  req.FormType,
166			FormID:    req.FormID,
167			StateJSON: req.StateJSON,
168			SavedAt:   time.Now(),
169		}
170	
171		if err := h.repo.SaveDraft(draft); err != nil {
172			logrus.WithError(err).Error("Failed to save draft")
173			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
174				Error: "Failed to save draft",
175				Code:  http.StatusInternalServerError,
176			})
177		}
178	
179		logrus.WithFields(logrus.Fields{
180			"user_id":  userID,
181			"draft_id": draft.ID,
182		}).Info("Draft saved")
183	
184		return c.JSON(http.StatusCreated, draft)
185	}
