205	// GetDraft returns a single draft by ID.
206	func (h *SystemHandler) GetDraft(c echo.Context) error {
207		id := c.Param("id")
208		if id == "" {
209			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
210				Error: "Draft ID is required",
211				Code:  http.StatusBadRequest,
212			})
213		}
214	
215		draft, err := h.repo.GetDraftByID(id)
216		if err != nil {
217			return c.JSON(http.StatusNotFound, models.ErrorResponse{
218				Error:   "Draft not found",
219				Code:    http.StatusNotFound,
220				Details: "No draft found with the given ID",
221			})
222		}
223	
224		// Ensure user can only access their own drafts
225		userID := middleware.GetUserID(c)
226		if draft.UserID != userID {
227			role := middleware.GetUserRole(c)
228			if role != "admin" {
229				return c.JSON(http.StatusForbidden, models.ErrorResponse{
230					Error:   "Access denied",
231					Code:    http.StatusForbidden,
232					Details: "You can only access your own drafts",
233				})
234			}
235		}
236	
237		return c.JSON(http.StatusOK, draft)
238	}
