125	func (r *Repository) LockUser(userID string, until time.Time) error {
126		_, err := r.DB.Exec(
127			`UPDATE auth_users SET locked_until = $1, updated_at = NOW() WHERE id = $2`, until, userID,
128		)
129		if err != nil {
130			return fmt.Errorf("lock user: %w", err)
131		}
132		return nil
133	}
134	
135	// UnlockUser removes the lock on a user account and resets failed attempts.
136	func (r *Repository) UnlockUser(userID string) error {
137		_, err := r.DB.Exec(
138			`UPDATE auth_users SET locked_until = NULL, failed_attempts = 0, updated_at = NOW() WHERE id = $1`, userID,
139		)
140		if err != nil {
141			return fmt.Errorf("unlock user: %w", err)
142		}
143		return nil
144	}
