16	// Context keys for user info
17	const (
18		contextKeyUserID   = "user_id"
19		contextKeyUserRole = "user_role"
20	)
21	
22	// GetUserID extracts the user_id from the echo context.
23	func GetUserID(c echo.Context) string {
24		val, _ := c.Get(contextKeyUserID).(string)
25		return val
26	}
27	
28	// GetUserRole extracts the user_role from the echo context.
29	func GetUserRole(c echo.Context) string {
30		val, _ := c.Get(contextKeyUserRole).(string)
31		return val
32	}
