import (
	"database/sql"

	"medops/internal/models"
)

// Repository provides data access methods backed by a SQL database.
type Repository struct {
	db *sql.DB
}

// New creates a new Repository with the given database connection.
func New(db *sql.DB) *Repository {
	return &Repository{db: db}
}

// DB returns the underlying database connection for use in migrations, etc.
func (r *Repository) DB() *sql.DB {
	return r.db
}

// --- Users ---

func (r *Repository) GetUserByUsername(username string) (*models.User, error) {
	u := &models.User{}
	err := r.db.QueryRow(
		`SELECT id, username, password_hash, role, failed_attempts, locked_until, is_active, created_at, updated_at
		 FROM users WHERE username = $1`, username,
	).Scan(&u.ID, &u.Username, &u.PasswordHash, &u.Role, &u.FailedAttempts, &u.LockedUntil, &u.IsActive, &u.CreatedAt, &u.UpdatedAt)
	if err != nil {
		return nil, err
	}
	return u, nil
}

func (r *Repository) GetUserByID(id string) (*models.User, error) {
	u := &models.User{}
	err := r.db.QueryRow(
		`SELECT id, username, password_hash, role, failed_attempts, locked_until, is_active, created_at, updated_at
		 FROM users WHERE id = $1`, id,
	).Scan(&u.ID, &u.Username, &u.PasswordHash, &u.Role, &u.FailedAttempts, &u.LockedUntil, &u.IsActive, &u.CreatedAt, &u.UpdatedAt)
	if err != nil {
		return nil, err
	}
	return u, nil
}

func (r *Repository) ListUsers() ([]models.User, error) {
	rows, err := r.db.Query(
		`SELECT id, username, password_hash, role, failed_attempts, locked_until, is_active, created_at, updated_at
		 FROM users ORDER BY created_at DESC`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var users []models.User
	for rows.Next() {
		var u models.User
		if err := rows.Scan(&u.ID, &u.Username, &u.PasswordHash, &u.Role, &u.FailedAttempts, &u.LockedUntil, &u.IsActive, &u.CreatedAt, &u.UpdatedAt); err != nil {
			return nil, err
		}
		users = append(users, u)
	}
	return users, nil
}

func (r *Repository) CreateUser(user *models.User) error {
	_, err := r.db.Exec(
		`INSERT INTO users (id, username, password_hash, role, failed_attempts, is_active, created_at, updated_at)
		 VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
		user.ID, user.Username, user.PasswordHash, user.Role, user.FailedAttempts, user.IsActive, user.CreatedAt, user.UpdatedAt,
	)
	return err
}

func (r *Repository) UpdateUser(user *models.User) error {
	_, err := r.db.Exec(
		`UPDATE users SET username=$2, password_hash=$3, role=$4, failed_attempts=$5, locked_until=$6, is_active=$7, updated_at=$8
		 WHERE id=$1`,
		user.ID, user.Username, user.PasswordHash, user.Role, user.FailedAttempts, user.LockedUntil, user.IsActive, user.UpdatedAt,
	)
	return err
}

func (r *Repository) IncrementFailedAttempts(userID string) error {
	_, err := r.db.Exec(`UPDATE users SET failed_attempts = failed_attempts + 1 WHERE id = $1`, userID)
	return err
}

func (r *Repository) LockUser(userID string, minutes int) error {
	_, err := r.db.Exec(
		`UPDATE users SET locked_until = NOW() + ($2 || ' minutes')::interval WHERE id = $1`,
		userID, minutes,
	)
	return err
}

func (r *Repository) ResetFailedAttempts(userID string) error {
	_, err := r.db.Exec(`UPDATE users SET failed_attempts = 0, locked_until = NULL WHERE id = $1`, userID)
	return err
}

func (r *Repository) UnlockUser(userID string) error {
	_, err := r.db.Exec(`UPDATE users SET failed_attempts = 0, locked_until = NULL WHERE id = $1`, userID)
	return err
}

// --- Inventory ---

func (r *Repository) ListSKUs(search string, page, pageSize int) ([]models.SKU, int, error) {
	offset := (page - 1) * pageSize
	var total int
	var rows *sql.Rows
	var err error

	if search != "" {
		searchPattern := "%" + search + "%"
		err = r.db.QueryRow(`SELECT COUNT(*) FROM skus WHERE name ILIKE $1 OR description ILIKE $1`, searchPattern).Scan(&total)
		if err != nil {
			return nil, 0, err
		}
		rows, err = r.db.Query(
			`SELECT id, ndc, upc, name, description, unit_of_measure, low_stock_threshold, storage_location, is_active, created_at
			 FROM skus WHERE name ILIKE $1 OR description ILIKE $1 ORDER BY name LIMIT $2 OFFSET $3`,
			searchPattern, pageSize, offset,
		)
	} else {
		err = r.db.QueryRow(`SELECT COUNT(*) FROM skus`).Scan(&total)
		if err != nil {
			return nil, 0, err
		}
		rows, err = r.db.Query(
			`SELECT id, ndc, upc, name, description, unit_of_measure, low_stock_threshold, storage_location, is_active, created_at
			 FROM skus ORDER BY name LIMIT $1 OFFSET $2`,
			pageSize, offset,
		)
	}
	if err != nil {
		return nil, 0, err
	}
	defer rows.Close()

	var skus []models.SKU
	for rows.Next() {
		var s models.SKU
		if err := rows.Scan(&s.ID, &s.NDC, &s.UPC, &s.Name, &s.Description, &s.UnitOfMeasure, &s.LowStockThreshold, &s.StorageLocation, &s.IsActive, &s.CreatedAt); err != nil {
			return nil, 0, err
		}
		skus = append(skus, s)
	}
	return skus, total, nil
}

