		if err := rows.Scan(&s.ID, &s.NDC, &s.UPC, &s.Name, &s.Description, &s.UnitOfMeasure, &s.LowStockThreshold, &s.StorageLocation, &s.IsActive, &s.CreatedAt); err != nil {
