		if err := rows.Scan(&t.ID, &t.SKUID, &t.BatchID, &t.Type, &t.Quantity, &t.ReasonCode, &t.PrescriptionID, &t.PerformedBy, &t.CreatedAt); err != nil {
			return nil, 0, err
		}
		txns = append(txns, t)
	}
	return txns, total, nil
}

// --- Stocktake ---

