func (r *Repository) GetWorkOrderAnalytics() (map[string]interface{}, error) {
	analytics := make(map[string]interface{})

	// Total count
	var total int
	r.db.QueryRow(`SELECT COUNT(*) FROM work_orders`).Scan(&total)
	analytics["total"] = total

	// By status
	byStatus := make(map[string]int)
	rows, err := r.db.Query(`SELECT status, COUNT(*) FROM work_orders GROUP BY status`)
	if err == nil {
		defer rows.Close()
		for rows.Next() {
			var status string
			var count int
			if err := rows.Scan(&status, &count); err == nil {
				byStatus[status] = count
			}
		}
	}
	analytics["by_status"] = byStatus

	// By priority
	byPriority := make(map[string]int)
	rows2, err := r.db.Query(`SELECT priority, COUNT(*) FROM work_orders GROUP BY priority`)
	if err == nil {
		defer rows2.Close()
		for rows2.Next() {
			var priority string
			var count int
			if err := rows2.Scan(&priority, &count); err == nil {
				byPriority[priority] = count
			}
		}
	}
	analytics["by_priority"] = byPriority

	// Average rating
	var avgRating sql.NullFloat64
	r.db.QueryRow(`SELECT AVG(rating) FROM work_orders WHERE rating IS NOT NULL`).Scan(&avgRating)
	if avgRating.Valid {
		analytics["avg_rating"] = avgRating.Float64
	} else {
		analytics["avg_rating"] = 0
	}

	// SLA compliance
	var totalCompleted, slaCompliant int
	r.db.QueryRow(`SELECT COUNT(*) FROM work_orders WHERE status = 'completed'`).Scan(&totalCompleted)
	r.db.QueryRow(`SELECT COUNT(*) FROM work_orders WHERE status = 'completed' AND (closed_at IS NULL OR closed_at <= sla_deadline)`).Scan(&slaCompliant)
	if totalCompleted > 0 {
		analytics["sla_compliance_pct"] = float64(slaCompliant) / float64(totalCompleted) * 100
	} else {
		analytics["sla_compliance_pct"] = 0
	}

	return analytics, nil
}

