func (r *Repository) ListWorkOrders(status, assignedTo string, page, pageSize int) ([]models.WorkOrder, int, error) {
	offset := (page - 1) * pageSize
	var total int

	query := `SELECT id, submitted_by, assigned_to, trade, priority, sla_deadline, status, description, location, parts_cost, labor_cost, rating, closed_at, created_at FROM work_orders`
	countQuery := `SELECT COUNT(*) FROM work_orders`
	var conditions []string
	var args []interface{}
	argIdx := 1

	if status != "" {
		conditions = append(conditions, "status = $"+itoa(argIdx))
		args = append(args, status)
		argIdx++
	}
	if assignedTo != "" {
		conditions = append(conditions, "assigned_to = $"+itoa(argIdx))
		args = append(args, assignedTo)
		argIdx++
	}

	if len(conditions) > 0 {
		where := " WHERE " + join(conditions, " AND ")
		query += where
		countQuery += where
	}

	err := r.db.QueryRow(countQuery, args...).Scan(&total)
	if err != nil {
		return nil, 0, err
	}

	query += " ORDER BY created_at DESC LIMIT $" + itoa(argIdx) + " OFFSET $" + itoa(argIdx+1)
	args = append(args, pageSize, offset)

	rows, err := r.db.Query(query, args...)
	if err != nil {
		return nil, 0, err
	}
	defer rows.Close()

	var wos []models.WorkOrder
	for rows.Next() {
		var wo models.WorkOrder
		if err := rows.Scan(&wo.ID, &wo.SubmittedBy, &wo.AssignedTo, &wo.Trade, &wo.Priority, &wo.SLADeadline, &wo.Status, &wo.Description, &wo.Location, &wo.PartsCost, &wo.LaborCost, &wo.Rating, &wo.ClosedAt, &wo.CreatedAt); err != nil {
			return nil, 0, err
		}
		wos = append(wos, wo)
	}
	return wos, total, nil
}

