		 WHERE id=$1`,
		st.ID, st.TotalAmount, st.Status, st.ApprovedBy1, st.ApprovedBy2, st.VarianceNotes, st.ExportedAt,
	)
	return err
}

func (r *Repository) CreateChargeLineItem(item *models.ChargeLineItem) error {
	_, err := r.db.Exec(
		`INSERT INTO charge_line_items (id, statement_id, description, quantity, unit_price, surcharge, tax, total)
		 VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
		item.ID, item.StatementID, item.Description, item.Quantity, item.UnitPrice, item.Surcharge, item.Tax, item.Total,
	)
	return err
}

// --- Files ---

func (r *Repository) GetFileByHash(sha256Hash string) (*models.ManagedFile, error) {
	f := &models.ManagedFile{}
	err := r.db.QueryRow(
		`SELECT id, sha256, original_name, mime_type, size_bytes, storage_path, retention_until, created_at
		 FROM managed_files WHERE sha256 = $1`, sha256Hash,
	).Scan(&f.ID, &f.SHA256, &f.OriginalName, &f.MimeType, &f.SizeBytes, &f.StoragePath, &f.RetentionUntil, &f.CreatedAt)
	if err != nil {
		return nil, err
	}
	return f, nil
}

func (r *Repository) CreateFile(f *models.ManagedFile) error {
	_, err := r.db.Exec(
		`INSERT INTO managed_files (id, sha256, original_name, mime_type, size_bytes, storage_path, retention_until, created_at)
		 VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
		f.ID, f.SHA256, f.OriginalName, f.MimeType, f.SizeBytes, f.StoragePath, f.RetentionUntil, f.CreatedAt,
	)
	return err
}

func (r *Repository) GetFileByID(id string) (*models.ManagedFile, error) {
	f := &models.ManagedFile{}
	err := r.db.QueryRow(
		`SELECT id, sha256, original_name, mime_type, size_bytes, storage_path, retention_until, created_at
		 FROM managed_files WHERE id = $1`, id,
	).Scan(&f.ID, &f.SHA256, &f.OriginalName, &f.MimeType, &f.SizeBytes, &f.StoragePath, &f.RetentionUntil, &f.CreatedAt)
	if err != nil {
		return nil, err
	}
	return f, nil
}

func (r *Repository) GetFilesByIDs(ids []string) ([]models.ManagedFile, error) {
	if len(ids) == 0 {
		return nil, nil
	}

	// Build placeholder string
	placeholders := ""
	args := make([]interface{}, len(ids))
	for i, id := range ids {
		if i > 0 {
			placeholders += ", "
		}
		placeholders += "$" + itoa(i+1)
		args[i] = id
	}

	rows, err := r.db.Query(
		`SELECT id, sha256, original_name, mime_type, size_bytes, storage_path, retention_until, created_at
		 FROM managed_files WHERE id IN (`+placeholders+`)`, args...,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var files []models.ManagedFile
	for rows.Next() {
		var f models.ManagedFile
		if err := rows.Scan(&f.ID, &f.SHA256, &f.OriginalName, &f.MimeType, &f.SizeBytes, &f.StoragePath, &f.RetentionUntil, &f.CreatedAt); err != nil {
			return nil, err
		}
		files = append(files, f)
	}
	return files, nil
}

