	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var drafts []models.DraftCheckpoint
	for rows.Next() {
		var d models.DraftCheckpoint
		if err := rows.Scan(&d.ID, &d.UserID, &d.FormType, &d.FormID, &d.StateJSON, &d.SavedAt); err != nil {
			return nil, err
		}
		drafts = append(drafts, d)
	}
	return drafts, nil
}

func (r *Repository) GetDraftByID(id string) (*models.DraftCheckpoint, error) {
	d := &models.DraftCheckpoint{}
	err := r.db.QueryRow(
		`SELECT id, user_id, form_type, form_id, state_json, saved_at
		 FROM draft_checkpoints WHERE id = $1`, id,
	).Scan(&d.ID, &d.UserID, &d.FormType, &d.FormID, &d.StateJSON, &d.SavedAt)
	if err != nil {
		return nil, err
	}
	return d, nil
}

func (r *Repository) DeleteDraft(id string) error {
	_, err := r.db.Exec(`DELETE FROM draft_checkpoints WHERE id = $1`, id)
	return err
}

// --- Audit ---

func (r *Repository) CreateAuditLog(entry *models.AuditLogEntry) error {
	_, err := r.db.Exec(
		`INSERT INTO audit_log (user_id, action, entity_type, entity_id, details, created_at)
		 VALUES ($1, $2, $3, $4, $5, $6)`,
		entry.UserID, entry.Action, entry.EntityType, entry.EntityID, entry.Details, entry.CreatedAt,
	)
	return err
}

// --- helpers ---

func itoa(i int) string {
	return fmt.Sprintf("%d", i)
}

func join(strs []string, sep string) string {
	result := ""
	for i, s := range strs {
		if i > 0 {
			result += sep
		}
		result += s
	}
	return result
}

// Import guards
var (
	_ = fmt.Sprintf
	_ = json.Marshal
)
"}

