// PostgresRepository implements the Repository interface using PostgreSQL.
type PostgresRepository struct {
	db *sql.DB
}

// NewPostgres creates a new PostgresRepository with the given database connection.
func NewPostgres(db *sql.DB) *PostgresRepository {
	return &PostgresRepository{db: db}
}

// ---------- Auth / Users ----------

// GetUserByUsername retrieves a user by their username.
func (r *PostgresRepository) GetUserByUsername(username string) (*models.User, error) {
	u := &models.User{}
	err := r.db.QueryRow(
		`SELECT id, username, password_hash, role, failed_attempts, locked_until, is_active, created_at, updated_at
		 FROM auth_users WHERE username = $1`, username,
	).Scan(&u.ID, &u.Username, &u.PasswordHash, &u.Role, &u.FailedAttempts, &u.LockedUntil, &u.IsActive, &u.CreatedAt, &u.UpdatedAt)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("get user by username: %w", err)
	}
	return u, nil
}

// GetUserByID retrieves a user by their ID.
func (r *PostgresRepository) GetUserByID(id string) (*models.User, error) {
	u := &models.User{}
	err := r.db.QueryRow(
		`SELECT id, username, password_hash, role, failed_attempts, locked_until, is_active, created_at, updated_at
		 FROM auth_users WHERE id = $1`, id,
	).Scan(&u.ID, &u.Username, &u.PasswordHash, &u.Role, &u.FailedAttempts, &u.LockedUntil, &u.IsActive, &u.CreatedAt, &u.UpdatedAt)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("get user by id: %w", err)
	}
	return u, nil
}

// ListUsers returns all users ordered by creation date.
func (r *PostgresRepository) ListUsers() ([]models.User, error) {
	rows, err := r.db.Query(
		`SELECT id, username, password_hash, role, failed_attempts, locked_until, is_active, created_at, updated_at
		 FROM auth_users ORDER BY created_at DESC`,
	)
	if err != nil {
		return nil, fmt.Errorf("list users: %w", err)
	}
	defer rows.Close()

	var users []models.User
	for rows.Next() {
		var u models.User
		if err := rows.Scan(&u.ID, &u.Username, &u.PasswordHash, &u.Role, &u.FailedAttempts, &u.LockedUntil, &u.IsActive, &u.CreatedAt, &u.UpdatedAt); err != nil {
			return nil, fmt.Errorf("list users scan: %w", err)
		}
		users = append(users, u)
	}
	return users, rows.Err()
}

// CreateUser inserts a new user into the database.
func (r *PostgresRepository) CreateUser(user *models.User) error {
	if user.ID == "" {
		user.ID = uuid.New().String()
	}
	now := time.Now()
	user.CreatedAt = now
	user.UpdatedAt = now
	_, err := r.db.Exec(
		`INSERT INTO auth_users (id, username, password_hash, role, failed_attempts, locked_until, is_active, created_at, updated_at)
		 VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)`,
		user.ID, user.Username, user.PasswordHash, user.Role, user.FailedAttempts, user.LockedUntil, user.IsActive, user.CreatedAt, user.UpdatedAt,
	)
	if err != nil {
		return fmt.Errorf("create user: %w", err)
	}
	return nil
}

// UpdateUser updates an existing user.
func (r *PostgresRepository) UpdateUser(user *models.User) error {
	user.UpdatedAt = time.Now()
	_, err := r.db.Exec(
		`UPDATE auth_users SET username=$1, password_hash=$2, role=$3, is_active=$4, updated_at=$5 WHERE id=$6`,
		user.Username, user.PasswordHash, user.Role, user.IsActive, user.UpdatedAt, user.ID,
	)
	if err != nil {
		return fmt.Errorf("update user: %w", err)
	}
	return nil
}

// IncrementFailedAttempts increments the failed login attempts counter.
func (r *PostgresRepository) IncrementFailedAttempts(userID string) error {
	_, err := r.db.Exec(
		`UPDATE auth_users SET failed_attempts = failed_attempts + 1, updated_at = NOW() WHERE id = $1`, userID,
	)
	if err != nil {
		return fmt.Errorf("increment failed attempts: %w", err)
	}
	return nil
}

// LockUser locks a user account for the specified number of minutes.
func (r *PostgresRepository) LockUser(userID string, minutes int) error {
	_, err := r.db.Exec(
		`UPDATE auth_users SET locked_until = NOW() + ($1 || ' minutes')::interval, updated_at = NOW() WHERE id = $2`,
		fmt.Sprintf("%d", minutes), userID,
	)
	if err != nil {
		return fmt.Errorf("lock user: %w", err)
	}
	return nil
}

// ResetFailedAttempts resets the failed login attempts counter to zero.
func (r *PostgresRepository) ResetFailedAttempts(userID string) error {
	_, err := r.db.Exec(
		`UPDATE auth_users SET failed_attempts = 0, updated_at = NOW() WHERE id = $1`, userID,
	)
	if err != nil {
		return fmt.Errorf("reset failed attempts: %w", err)
	}
	return nil
}

// UnlockUser removes the lock on a user account and resets failed attempts.
func (r *PostgresRepository) UnlockUser(userID string) error {
	_, err := r.db.Exec(
		`UPDATE auth_users SET locked_until = NULL, failed_attempts = 0, updated_at = NOW() WHERE id = $1`, userID,
	)
	if err != nil {
		return fmt.Errorf("unlock user: %w", err)
	}
	return nil
}

