// ListSKUs returns paginated SKUs with optional search on name/ndc/upc.
func (r *PostgresRepository) ListSKUs(search string, page, pageSize int) ([]models.SKU, int, error) {
	offset := (page - 1) * pageSize
	var rows *sql.Rows
	var err error

	if search != "" {
		pattern := "%" + search + "%"
		rows, err = r.db.Query(
			`SELECT id, ndc, upc, name, description, unit_of_measure, low_stock_threshold, storage_location, is_active, created_at,
			        COUNT(*) OVER() AS total
			 FROM skus
			 WHERE name ILIKE $1 OR ndc ILIKE $1 OR upc ILIKE $1
			 ORDER BY name
			 LIMIT $2 OFFSET $3`, pattern, pageSize, offset,
		)
	} else {
		rows, err = r.db.Query(
			`SELECT id, ndc, upc, name, description, unit_of_measure, low_stock_threshold, storage_location, is_active, created_at,
			        COUNT(*) OVER() AS total
			 FROM skus
			 ORDER BY name
			 LIMIT $1 OFFSET $2`, pageSize, offset,
		)
	}
	if err != nil {
		return nil, 0, fmt.Errorf("list skus: %w", err)
	}
	defer rows.Close()

	var skus []models.SKU
	var total int
	for rows.Next() {
		var s models.SKU
		if err := rows.Scan(&s.ID, &s.NDC, &s.UPC, &s.Name, &s.Description, &s.UnitOfMeasure, &s.LowStockThreshold, &s.StorageLocation, &s.IsActive, &s.CreatedAt, &total); err != nil {
