// GetLowStockSKUs returns active SKUs where total batch quantity is below threshold.
func (r *PostgresRepository) GetLowStockSKUs() ([]models.SKU, error) {
	rows, err := r.db.Query(
		`SELECT s.id, s.ndc, s.upc, s.name, s.description, s.unit_of_measure, s.low_stock_threshold, s.storage_location, s.is_active, s.created_at
		 FROM skus s
		 LEFT JOIN inventory_batches b ON b.sku_id = s.id
		 WHERE s.is_active = true
		 GROUP BY s.id, s.ndc, s.upc, s.name, s.description, s.unit_of_measure, s.low_stock_threshold, s.storage_location, s.is_active, s.created_at
		 HAVING COALESCE(SUM(b.quantity_on_hand), 0) < s.low_stock_threshold
		 ORDER BY s.name`,
	)
	if err != nil {
		return nil, fmt.Errorf("get low stock skus: %w", err)
	}
	defer rows.Close()

	var skus []models.SKU
	for rows.Next() {
		var s models.SKU
