	err := r.db.QueryRow(
		`SELECT u.id
		 FROM auth_users u
		 WHERE u.role = 'maintenance_tech' AND u.is_active = true
		 ORDER BY (
		   SELECT COUNT(*) FROM work_orders wo
		   WHERE wo.assigned_to = u.id AND wo.status IN ('open', 'in_progress')
		 ) ASC
		 LIMIT 1`,
	).Scan(&userID)
	if err == sql.ErrNoRows {
		return "", nil
	}
	if err != nil {
		return "", fmt.Errorf("get tech with least orders: %w", err)
	}
	return userID, nil
}

// GetWorkOrderAnalytics returns basic work order statistics.
func (r *PostgresRepository) GetWorkOrderAnalytics() (map[string]interface{}, error) {
	analytics := make(map[string]interface{})

	// Count by status
	rows, err := r.db.Query(`SELECT status, COUNT(*) FROM work_orders GROUP BY status`)
	if err != nil {
		return nil, fmt.Errorf("work order analytics by_status: %w", err)
	}
	defer rows.Close()

	statusCounts := make(map[string]int)
	for rows.Next() {
		var status string
		var count int
		if err := rows.Scan(&status, &count); err != nil {
			return nil, fmt.Errorf("work order analytics by_status scan: %w", err)
		}
		statusCounts[status] = count
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	analytics["by_status"] = statusCounts

	// Count by priority
	pRows, err := r.db.Query(`SELECT priority, COUNT(*) FROM work_orders GROUP BY priority`)
	if err != nil {
		return nil, fmt.Errorf("work order analytics by_priority: %w", err)
	}
	defer pRows.Close()

	priorityCounts := make(map[string]int)
	for pRows.Next() {
		var priority string
		var count int
		if err := pRows.Scan(&priority, &count); err != nil {
			return nil, fmt.Errorf("work order analytics by_priority scan: %w", err)
		}
		priorityCounts[priority] = count
	}
	if err := pRows.Err(); err != nil {
		return nil, err
	}
	analytics["by_priority"] = priorityCounts

	// Average resolution time (hours) for closed orders
	var avgHours sql.NullFloat64
	err = r.db.QueryRow(
		`SELECT AVG(EXTRACT(EPOCH FROM (closed_at - created_at)) / 3600)
		 FROM work_orders WHERE status = 'closed' AND closed_at IS NOT NULL`,
	).Scan(&avgHours)
	if err != nil {
		return nil, fmt.Errorf("work order analytics avg_resolution: %w", err)
	}
	if avgHours.Valid {
		analytics["avg_resolution_hours"] = avgHours.Float64
	} else {
		analytics["avg_resolution_hours"] = 0
	}

	// Total costs for closed orders
	var totalParts, totalLabor sql.NullFloat64
	err = r.db.QueryRow(
		`SELECT COALESCE(SUM(parts_cost), 0), COALESCE(SUM(labor_cost), 0) FROM work_orders WHERE status = 'closed'`,
	).Scan(&totalParts, &totalLabor)
	if err != nil {
		return nil, fmt.Errorf("work order analytics costs: %w", err)
	}
	analytics["total_parts_cost"] = totalParts.Float64
	analytics["total_labor_cost"] = totalLabor.Float64

	// Average rating
	var avgRating sql.NullFloat64
	err = r.db.QueryRow(`SELECT AVG(rating) FROM work_orders WHERE rating IS NOT NULL`).Scan(&avgRating)
	if err != nil {
		return nil, fmt.Errorf("work order analytics avg_rating: %w", err)
	}
	if avgRating.Valid {
		analytics["avg_rating"] = avgRating.Float64
	} else {
		analytics["avg_rating"] = 0
	}

	return analytics, nil
}

