	f.CreatedAt = time.Now()
	_, err := r.db.Exec(
		`INSERT INTO managed_files (id, sha256, original_name, mime_type, size_bytes, storage_path, retention_until, created_at)
		 VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
		f.ID, f.SHA256, f.OriginalName, f.MimeType, f.SizeBytes, f.StoragePath, f.RetentionUntil, f.CreatedAt,
	)
	if err != nil {
		return fmt.Errorf("create file: %w", err)
	}
	return nil
}

// GetFileByID retrieves a managed file by ID.
func (r *PostgresRepository) GetFileByID(id string) (*models.ManagedFile, error) {
	f := &models.ManagedFile{}
	err := r.db.QueryRow(
		`SELECT id, sha256, original_name, mime_type, size_bytes, storage_path, retention_until, created_at
		 FROM managed_files WHERE id = $1`, id,
	).Scan(&f.ID, &f.SHA256, &f.OriginalName, &f.MimeType, &f.SizeBytes, &f.StoragePath, &f.RetentionUntil, &f.CreatedAt)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("get file by id: %w", err)
	}
	return f, nil
}

// GetFilesByIDs retrieves multiple managed files by their IDs.
func (r *PostgresRepository) GetFilesByIDs(ids []string) ([]models.ManagedFile, error) {
	if len(ids) == 0 {
		return nil, nil
	}

	// Build placeholders for IN clause
	placeholders := make([]string, len(ids))
	args := make([]interface{}, len(ids))
	for i, id := range ids {
		placeholders[i] = fmt.Sprintf("$%d", i+1)
		args[i] = id
	}

	query := fmt.Sprintf(
		`SELECT id, sha256, original_name, mime_type, size_bytes, storage_path, retention_until, created_at
		 FROM managed_files WHERE id IN (%s) ORDER BY created_at`,
		strings.Join(placeholders, ", "),
	)

	rows, err := r.db.Query(query, args...)
	if err != nil {
		return nil, fmt.Errorf("get files by ids: %w", err)
	}
	defer rows.Close()

	var files []models.ManagedFile
	for rows.Next() {
		var f models.ManagedFile
		if err := rows.Scan(&f.ID, &f.SHA256, &f.OriginalName, &f.MimeType, &f.SizeBytes, &f.StoragePath, &f.RetentionUntil, &f.CreatedAt); err != nil {
			return nil, fmt.Errorf("get files by ids scan: %w", err)
		}
		files = append(files, f)
	}
	return files, rows.Err()
}

// ---------- Config ----------

// GetConfig retrieves all configuration key-value pairs.
func (r *PostgresRepository) GetConfig() (map[string]string, error) {
	config := make(map[string]string)
	rows, err := r.db.Query(`SELECT key, value FROM app_config`)
	if err != nil {
		// If table doesn't exist, return empty map
		return config, nil
	}
	defer rows.Close()

	for rows.Next() {
		var key, value string
		if err := rows.Scan(&key, &value); err != nil {
			return nil, fmt.Errorf("get config scan: %w", err)
		}
		config[key] = value
	}
	return config, rows.Err()
}

// UpdateConfig upserts a single configuration key-value pair.
func (r *PostgresRepository) UpdateConfig(key, value string) error {
	_, err := r.db.Exec(
		`INSERT INTO app_config (key, value) VALUES ($1, $2)
		 ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value`,
		key, value,
	)
	if err != nil {
		return fmt.Errorf("update config: %w", err)
	}
	return nil
}

// ---------- Drafts ----------

// SaveDraft upserts a draft checkpoint by user_id+form_type.
func (r *PostgresRepository) SaveDraft(d *models.DraftCheckpoint) error {
	if d.ID == "" {
		d.ID = uuid.New().String()
	}
	d.SavedAt = time.Now()
	_, err := r.db.Exec(
		`INSERT INTO draft_checkpoints (id, user_id, form_type, form_id, state_json, saved_at)
		 VALUES ($1, $2, $3, $4, $5, $6)
		 ON CONFLICT (user_id, form_type) DO UPDATE
		 SET state_json = EXCLUDED.state_json, saved_at = EXCLUDED.saved_at, form_id = EXCLUDED.form_id`,
		d.ID, d.UserID, d.FormType, d.FormID, d.StateJSON, d.SavedAt,
	)
	if err != nil {
		return fmt.Errorf("save draft: %w", err)
	}
	return nil
}

// ListDrafts returns all drafts for a given user.
func (r *PostgresRepository) ListDrafts(userID string) ([]models.DraftCheckpoint, error) {
	rows, err := r.db.Query(
		`SELECT id, user_id, form_type, form_id, state_json, saved_at
		 FROM draft_checkpoints WHERE user_id = $1 ORDER BY saved_at DESC`, userID,
	)
	if err != nil {
		return nil, fmt.Errorf("list drafts: %w", err)
	}
	defer rows.Close()

	var drafts []models.DraftCheckpoint
	for rows.Next() {
		var d models.DraftCheckpoint
		if err := rows.Scan(&d.ID, &d.UserID, &d.FormType, &d.FormID, &d.StateJSON, &d.SavedAt); err != nil {
			return nil, fmt.Errorf("list drafts scan: %w", err)
		}
		drafts = append(drafts, d)
	}
	return drafts, rows.Err()
}

// GetDraftByID retrieves a specific draft by its ID.
func (r *PostgresRepository) GetDraftByID(id string) (*models.DraftCheckpoint, error) {
	d := &models.DraftCheckpoint{}
	err := r.db.QueryRow(
		`SELECT id, user_id, form_type, form_id, state_json, saved_at
		 FROM draft_checkpoints WHERE id = $1`, id,
	).Scan(&d.ID, &d.UserID, &d.FormType, &d.FormID, &d.StateJSON, &d.SavedAt)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("get draft by id: %w", err)
	}
	return d, nil
}

// DeleteDraft removes a draft by its ID.
func (r *PostgresRepository) DeleteDraft(id string) error {
	_, err := r.db.Exec(
		`DELETE FROM draft_checkpoints WHERE id = $1`, id,
	)
	if err != nil {
		return fmt.Errorf("delete draft: %w", err)
	}
	return nil
}

// DeleteDraftByID is an alias for DeleteDraft for compatibility.
func (r *PostgresRepository) DeleteDraftByID(id string) error {
	return r.DeleteDraft(id)
}

// ---------- Audit ----------

// CreateAuditLog inserts a new audit log entry.
func (r *PostgresRepository) CreateAuditLog(entry *models.AuditLogEntry) error {
	entry.CreatedAt = time.Now()
	_, err := r.db.Exec(
		`INSERT INTO audit_log (user_id, action, entity_type, entity_id, details, created_at)
		 VALUES ($1, $2, $3, $4, $5, $6)`,
		entry.UserID, entry.Action, entry.EntityType, entry.EntityID, entry.Details, entry.CreatedAt,
	)
	if err != nil {
		return fmt.Errorf("create audit log: %w", err)
	}
	return nil
}

